proverif_model.model_code:
(* ProVerif model for Matter Level Control Cluster *)
(* Generated from FSM specification *)

(* === Type Declarations === *)
type state.
type command.
type endpoint.
type mode.
type options.
type level.
type time.
type rate.
type step.
type frequency.
type boolv.

(* === Channel Declarations === *)
free c_cmd: channel.                 (* Public command channel: client -> server *)
free c_resp: channel.                (* Public response channel: server -> client *)
free c_internal: channel [private].  (* Internal state channel *)

(* === State Constants === *)
const st_OffState: state.
const st_OnState: state.

(* === Command/Trigger Constants === *)
const cmd_Startup: command.
const cmd_MoveToLevel: command.
const cmd_Move: command.
const cmd_Step: command.
const cmd_Stop: command.
const cmd_MoveToLevelWithOnOff: command.
const cmd_MoveWithOnOff: command.
const cmd_StepWithOnOff: command.
const cmd_StopWithOnOff: command.
const cmd_MoveToClosestFrequency: command.

(* === Value / Attribute Domain Constants === *)
(* Boolean-like values for guards and attributes *)
const v_true: boolv.
const v_false: boolv.

(* Move / Step mode enumerations *)
const v_Up: mode.
const v_Down: mode.

(* Special options / bitmap placeholders *)
const v_execIfOff0: options.
const v_execIfOff1: options.

(* Generic constants for attributes / levels / times / rates / frequencies *)
(* We do not model concrete numeric ranges; these are symbolic. *)
const v_zero_time: time.
const v_zero_rate: rate.
const v_zero_step: step.
const v_zero_level: level.

(* === Events (Action Facts from FSM) === *)
event MoveToLevelReceived(endpoint, level, time, options, options).
event TempOptionsComputed(endpoint, options).
event MoveToLevelStarted(endpoint, level, level, time).
event MoveReceived(endpoint, mode, rate, options, options).
event MoveInvalidRateZero(endpoint).
event MoveEffectiveRateSelected(endpoint, rate).
event MoveStarted(endpoint, level, mode, rate).
event StepReceived(endpoint, mode, step, time, options, options).
event StepInvalidSizeZero(endpoint).
event StepTargetComputed(endpoint, level, level, time).
event StepStarted(endpoint, level, level, time).
event StopReceived(endpoint, options, options).
event LevelTransitionStopped(endpoint).
event MoveToLevelWithOnOffReceived(endpoint, level, time, options, options).
event OnOffUpdatedFromLevel(endpoint, level, level, boolv).
event MoveWithOnOffReceived(endpoint, mode, rate, options, options).
event MoveWithOnOffStarted(endpoint, level, mode, rate).
event StepWithOnOffReceived(endpoint, mode, step, time, options, options).
event StepWithOnOffStarted(endpoint, level, level, time).
event StopWithOnOffReceived(endpoint, options, options).
event MoveToClosestFrequencyReceived(endpoint, frequency).
event ClosestFrequencySelected(endpoint, frequency, frequency).
event MoveToClosestFrequencyConstraintError(endpoint, frequency).
event StartupOccurred(endpoint).
event StartupCurrentLevelRestoredPrevious(endpoint, level).
event StartupCurrentLevelForcedMin(endpoint, level).
event StartupCurrentLevelForcedValue(endpoint, level).
event ExecuteIfOffEvaluated(endpoint, options, boolv).

(* State-change oriented events (for possible reachability/correspondence checks) *)
event StateChanged(endpoint, state, state).
event Attribute_CurrentLevel(endpoint, level).
event Attribute_OnOff(endpoint, boolv).
event Attribute_RemainingTime(endpoint, time).
event Attribute_CurrentFrequency(endpoint, frequency).

(* === Queries (placeholders; model is mainly reachability-oriented) === *)
(* Example reachability queries for some key events *)
query ep: endpoint; event StartupOccurred(ep).
query ep: endpoint, l: level; event MoveToLevelStarted(ep, l, l, v_zero_time) ==> event MoveToLevelReceived(ep, l, v_zero_time, v_execIfOff0, v_execIfOff0).

(* === Helper Process: One Transition Step Given Current State and Command === *)
(* We encode all FSM transitions as a big case analysis on (state, command).
   Input parameters:
     ep         : endpoint identity
     st         : current state (st_OffState or st_OnState)
     curLevel   : current_level attribute
     devMin     : device_min_level
     devMax     : device_max_level
     onoffAttr  : onoff attribute (v_true / v_false)
     remTime    : RemainingTime attribute
     curFreq    : CurrentFrequency attribute
   Output:
     updated state and attributes via c_internal.
*)

let DeviceStep(
  ep: endpoint,
  st: state,
  curLevel: level,
  devMin: level,
  devMax: level,
  onoffAttr: boolv,
  remTime: time,
  curFreq: frequency
) =
  in(c_cmd, cmd: command);

  (* For each command we non-deterministically pick parameter values.
     In a more precise extraction, the client message structure would be
     modeled explicitly; here we abstract to symbolic parameters. *)
  if cmd = cmd_Startup then
    (* Startup transitions (OffState only in FSM; if OnState, we keep it simple and stay OnState) *)
    if st = st_OffState then
      (* Three Startup variants; we model them as three nondet branches guarded by abstract booleans.
         We use fresh symbolic levels previous_level and startup_level and a symbolic min-level. *)
      new previous_level: level;
      new startup_level: level;
      (* Branch 1: T_Startup_RestorePrevious (StartUpCurrentLevel is null) *)
      (
        event StartupOccurred(ep);
        event StartupCurrentLevelRestoredPrevious(ep, previous_level);
        event Attribute_CurrentLevel(ep, previous_level);
        out(c_internal, (st_OffState, previous_level, devMin, devMax, onoffAttr, remTime, curFreq))
      )
      |
      (* Branch 2: T_Startup_ForceMin (StartUpCurrentLevel is 0) *)
      (
        event StartupOccurred(ep);
        event StartupCurrentLevelForcedMin(ep, devMin);
        event Attribute_CurrentLevel(ep, devMin);
        out(c_internal, (st_OffState, devMin, devMin, devMax, onoffAttr, remTime, curFreq))
      )
      |
      (* Branch 3: T_Startup_ForceValue (StartUpCurrentLevel non-null and non-zero) *)
      (
        event StartupOccurred(ep);
        event StartupCurrentLevelForcedValue(ep, startup_level);
        event Attribute_CurrentLevel(ep, startup_level);
        out(c_internal, (st_OffState, startup_level, devMin, devMax, onoffAttr, remTime, curFreq))
      )
    else
      (* If already OnState at startup, we leave attributes unchanged. *)
      event StartupOccurred(ep);
      out(c_internal, (st, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))

  else if cmd = cmd_MoveToLevel then
    (* Parameters for MoveToLevel *)
    new lvl: level;
    new trTime: time;
    new optMask: options;
    new optOverride: options;
    new tempOpt: options;
    new dur: time;
    event MoveToLevelReceived(ep, lvl, trTime, optMask, optOverride);
    event TempOptionsComputed(ep, tempOpt);

    if st = st_OffState then
      (* OffState transitions depending on execute_if_off and onoffAttr = v_false *)
      if onoffAttr = v_false then
        (* Abstractly encode two possibilities for execute_if_off: 0 or 1 *)
        (
          (* T_MoveToLevel_ExecuteIfOff0_Off_NoChange *)
          event ExecuteIfOffEvaluated(ep, v_execIfOff0, onoffAttr);
          (* No level change *)
          out(c_resp, cmd_MoveToLevel);
          out(c_internal, (st_OffState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))
        )
        |
        (
          (* T_MoveToLevel_ExecuteIfOff1_Off_UpdateLevel *)
          event ExecuteIfOffEvaluated(ep, v_execIfOff1, onoffAttr);
          event MoveToLevelStarted(ep, curLevel, lvl, dur);
          event Attribute_CurrentLevel(ep, lvl);
          out(c_resp, cmd_MoveToLevel);
          out(c_internal, (st_OffState, lvl, devMin, devMax, onoffAttr, remTime, curFreq))
        )
      else
        (* If somehow onoffAttr not v_false while st_OffState, we conservatively just keep state. *)
        out(c_resp, cmd_MoveToLevel);
        out(c_internal, (st_OffState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))
    else
      (* OnState transitions *)
      if onoffAttr = v_true then
        (* T_MoveToLevel_On_UpdateLevel *)
        event MoveToLevelStarted(ep, curLevel, lvl, dur);
        event Attribute_CurrentLevel(ep, lvl);
        out(c_resp, cmd_MoveToLevel);
        out(c_internal, (st_OnState, lvl, devMin, devMax, onoffAttr, remTime, curFreq))
      else
        (* If state is OnState but OnOff attribute not v_true, keep abstractly unchanged. *)
        out(c_resp, cmd_MoveToLevel);
        out(c_internal, (st_OnState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))

  else if cmd = cmd_Move then
    new mvMode: mode;
    new mvRate: rate;
    new optMaskM: options;
    new optOverrideM: options;
    new tempOptM: options;
    new effRate: rate;
    event MoveReceived(ep, mvMode, mvRate, optMaskM, optOverrideM);

    if st = st_OffState then
      (* OffState Move transitions *)
      (* T_Move_InvalidRateZero *)
      (
        event MoveInvalidRateZero(ep);
        out(c_resp, cmd_Move);
        out(c_internal, (st_OffState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))
      )
      |
      (
        (* Non-zero rate; abstract ExecuteIfOff = 1 cases for Up and Down *)
        event TempOptionsComputed(ep, tempOptM);
        event MoveEffectiveRateSelected(ep, effRate);
        if mvMode = v_Up then
          (* T_Move_ExecuteIfOff1_Off_UpdateLevelToMax *)
          event MoveStarted(ep, curLevel, v_Up, effRate);
          event Attribute_CurrentLevel(ep, devMax);
          out(c_resp, cmd_Move);
          out(c_internal, (st_OffState, devMax, devMin, devMax, onoffAttr, remTime, curFreq))
        else if mvMode = v_Down then
          (* No explicit 'Move down off-state' transition with ExecuteIfOff in FSM: keep abstract *)
          event MoveStarted(ep, curLevel, v_Down, effRate);
          out(c_resp, cmd_Move);
          out(c_internal, (st_OffState, devMin, devMin, devMax, onoffAttr, remTime, curFreq))
        else
          out(c_resp, cmd_Move);
          out(c_internal, (st_OffState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))
      )
    else
      (* OnState Move transitions *)
      if mvRate = v_zero_rate then
        (* InvalidCommand behavior; we record event and leave attributes *)
        event MoveInvalidRateZero(ep);
        out(c_resp, cmd_Move);
        out(c_internal, (st_OnState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))
      else
        event TempOptionsComputed(ep, tempOptM);
        event MoveEffectiveRateSelected(ep, effRate);
        if mvMode = v_Up then
          (* T_Move_On_UpToMax *)
          event MoveStarted(ep, curLevel, v_Up, effRate);
          event Attribute_CurrentLevel(ep, devMax);
          out(c_resp, cmd_Move);
          out(c_internal, (st_OnState, devMax, devMin, devMax, onoffAttr, remTime, curFreq))
        else if mvMode = v_Down then
          (* T_Move_On_DownToMin *)
          event MoveStarted(ep, curLevel, v_Down, effRate);
          event Attribute_CurrentLevel(ep, devMin);
          out(c_resp, cmd_Move);
          out(c_internal, (st_OnState, devMin, devMin, devMax, onoffAttr, remTime, curFreq))
        else
          out(c_resp, cmd_Move);
          out(c_internal, (st_OnState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))

  else if cmd = cmd_Step then
    new stMode: mode;
    new stSize: step;
    new trTimeS: time;
    new optMaskS: options;
    new optOverrideS: options;
    new tempOptS: options;
    new tgtLevelS: level;
    new durS: time;
    event StepReceived(ep, stMode, stSize, trTimeS, optMaskS, optOverrideS);

    if st = st_OffState then
      (* T_Step_InvalidSizeZero (off-state) *)
      event StepInvalidSizeZero(ep);
      out(c_resp, cmd_Step);
      out(c_internal, (st_OffState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))
    else
      (* OnState *)
      if stSize = v_zero_step then
        event StepInvalidSizeZero(ep);
        out(c_resp, cmd_Step);
        out(c_internal, (st_OnState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))
      else
        event TempOptionsComputed(ep, tempOptS);
        event StepTargetComputed(ep, curLevel, tgtLevelS, durS);
        event StepStarted(ep, curLevel, tgtLevelS, durS);
        event Attribute_CurrentLevel(ep, tgtLevelS);
        out(c_resp, cmd_Step);
        out(c_internal, (st_OnState, tgtLevelS, devMin, devMax, onoffAttr, remTime, curFreq))

  else if cmd = cmd_Stop then
    new optMaskStop: options;
    new optOverrideStop: options;
    new tempOptStop: options;
    event StopReceived(ep, optMaskStop, optOverrideStop);
    event TempOptionsComputed(ep, tempOptStop);
    event LevelTransitionStopped(ep);
    event Attribute_RemainingTime(ep, v_zero_time);
    out(c_resp, cmd_Stop);
    out(c_internal, (st, curLevel, devMin, devMax, onoffAttr, v_zero_time, curFreq))

  else if cmd = cmd_MoveToLevelWithOnOff then
    new lvlW: level;
    new trTimeW: time;
    new optMaskW: options;
    new optOverrideW: options;
    new tempOptW: options;
    new durW: time;
    event MoveToLevelWithOnOffReceived(ep, lvlW, trTimeW, optMaskW, optOverrideW);
    event TempOptionsComputed(ep, tempOptW);

    if st = st_OffState then
      (* T_MoveToLevelWithOnOff_Off_ExecuteIfOff0: Off -> On *)
      event MoveToLevelStarted(ep, curLevel, lvlW, durW);
      event OnOffUpdatedFromLevel(ep, lvlW, devMin, v_true);
      event Attribute_CurrentLevel(ep, lvlW);
      event Attribute_OnOff(ep, v_true);
      event StateChanged(ep, st_OffState, st_OnState);
      out(c_resp, cmd_MoveToLevelWithOnOff);
      out(c_internal, (st_OnState, lvlW, devMin, devMax, v_true, remTime, curFreq))
    else
      (* T_MoveToLevelWithOnOff_On *)
      event MoveToLevelStarted(ep, curLevel, lvlW, durW);
      event OnOffUpdatedFromLevel(ep, lvlW, devMin, v_true);
      event Attribute_CurrentLevel(ep, lvlW);
      event Attribute_OnOff(ep, v_true);
      out(c_resp, cmd_MoveToLevelWithOnOff);
      out(c_internal, (st_OnState, lvlW, devMin, devMax, v_true, remTime, curFreq))

  else if cmd = cmd_MoveWithOnOff then
    new mvModeW: mode;
    new mvRateW: rate;
    new optMaskMW: options;
    new optOverrideMW: options;
    new tempOptMW: options;
    new effRateW: rate;
    event MoveWithOnOffReceived(ep, mvModeW, mvRateW, optMaskMW, optOverrideMW);
    event TempOptionsComputed(ep, tempOptMW);
    event MoveEffectiveRateSelected(ep, effRateW);

    if st = st_OffState then
      if mvModeW = v_Up then
        (* T_MoveWithOnOff_Off_ExecuteIfOff1_UpToMax_On: Off -> On *)
        event MoveWithOnOffStarted(ep, curLevel, v_Up, effRateW);
        event OnOffUpdatedFromLevel(ep, devMax, devMin, v_true);
        event Attribute_CurrentLevel(ep, devMax);
        event Attribute_OnOff(ep, v_true);
        event StateChanged(ep, st_OffState, st_OnState);
        out(c_resp, cmd_MoveWithOnOff);
        out(c_internal, (st_OnState, devMax, devMin, devMax, v_true, remTime, curFreq))
      else if mvModeW = v_Down then
        (* T_MoveWithOnOff_Off_ExecuteIfOff1_DownToMin_StaysOff *)
        event MoveWithOnOffStarted(ep, curLevel, v_Down, effRateW);
        event OnOffUpdatedFromLevel(ep, devMin, devMin, v_false);
        event Attribute_CurrentLevel(ep, devMin);
        event Attribute_OnOff(ep, v_false);
        out(c_resp, cmd_MoveWithOnOff);
        out(c_internal, (st_OffState, devMin, devMin, devMax, v_false, remTime, curFreq))
      else
        out(c_resp, cmd_MoveWithOnOff);
        out(c_internal, (st_OffState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))
    else
      (* OnState *)
      if mvModeW = v_Up then
        (* T_MoveWithOnOff_On_UpToMax *)
        event MoveWithOnOffStarted(ep, curLevel, v_Up, effRateW);
        event OnOffUpdatedFromLevel(ep, devMax, devMin, v_true);
        event Attribute_CurrentLevel(ep, devMax);
        event Attribute_OnOff(ep, v_true);
        out(c_resp, cmd_MoveWithOnOff);
        out(c_internal, (st_OnState, devMax, devMin, devMax, v_true, remTime, curFreq))
      else if mvModeW = v_Down then
        (* T_MoveWithOnOff_On_DownToMin_AndOff: On -> Off *)
        event MoveWithOnOffStarted(ep, curLevel, v_Down, effRateW);
        event OnOffUpdatedFromLevel(ep, devMin, devMin, v_false);
        event Attribute_CurrentLevel(ep, devMin);
        event Attribute_OnOff(ep, v_false);
        event StateChanged(ep, st_OnState, st_OffState);
        out(c_resp, cmd_MoveWithOnOff);
        out(c_internal, (st_OffState, devMin, devMin, devMax, v_false, remTime, curFreq))
      else
        out(c_resp, cmd_MoveWithOnOff);
        out(c_internal, (st_OnState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))

  else if cmd = cmd_StepWithOnOff then
    new stModeW: mode;
    new stSizeW: step;
    new trTimeSW: time;
    new optMaskSW: options;
    new optOverrideSW: options;
    new tempOptSW: options;
    new tgtLevelSW: level;
    new durSW: time;
    new onoffRes: boolv;
    event StepWithOnOffReceived(ep, stModeW, stSizeW, trTimeSW, optMaskSW, optOverrideSW);

    if st = st_OnState then
      if stSizeW = v_zero_step then
        (* Invalid size; reuse StepInvalidSizeZero for withOnOff case *)
        event StepInvalidSizeZero(ep);
        out(c_resp, cmd_StepWithOnOff);
        out(c_internal, (st_OnState, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))
      else
        event TempOptionsComputed(ep, tempOptSW);
        event StepTargetComputed(ep, curLevel, tgtLevelSW, durSW);
        event StepWithOnOffStarted(ep, curLevel, tgtLevelSW, durSW);
        event OnOffUpdatedFromLevel(ep, tgtLevelSW, devMin, onoffRes);
        event Attribute_CurrentLevel(ep, tgtLevelSW);
        event Attribute_OnOff(ep, onoffRes);
        out(c_resp, cmd_StepWithOnOff);
        out(c_internal, (st_OnState, tgtLevelSW, devMin, devMax, onoffRes, remTime, curFreq))
    else
      (* If in OffState, we ignore StepWithOnOff for simplicity *)
      out(c_resp, cmd_StepWithOnOff);
      out(c_internal, (st, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))

  else if cmd = cmd_StopWithOnOff then
    new optMaskSWO: options;
    new optOverrideSWO: options;
    new tempOptSWO: options;
    event StopWithOnOffReceived(ep, optMaskSWO, optOverrideSWO);
    event TempOptionsComputed(ep, tempOptSWO);
    event LevelTransitionStopped(ep);
    event Attribute_RemainingTime(ep, v_zero_time);
    out(c_resp, cmd_StopWithOnOff);
    out(c_internal, (st, curLevel, devMin, devMax, onoffAttr, v_zero_time, curFreq))

  else if cmd = cmd_MoveToClosestFrequency then
    new freqReq: frequency;
    new freqSel: frequency;
    (* Two branches: success vs constraint error *)
    event MoveToClosestFrequencyReceived(ep, freqReq);
    (
      (* T_MoveToClosestFrequency_Success *)
      event ClosestFrequencySelected(ep, freqReq, freqSel);
      event Attribute_CurrentFrequency(ep, freqSel);
      out(c_resp, cmd_MoveToClosestFrequency);
      out(c_internal, (st, curLevel, devMin, devMax, onoffAttr, remTime, freqSel))
    )
    |
    (
      (* T_MoveToClosestFrequency_ConstraintError *)
      event MoveToClosestFrequencyConstraintError(ep, freqReq);
      out(c_resp, cmd_MoveToClosestFrequency);
      out(c_internal, (st, curLevel, devMin, devMax, onoffAttr, remTime, curFreq))
    )

  else
    (* Unknown command: no-op *)
    out(c_internal, (st, curLevel, devMin, devMax, onoffAttr, remTime, curFreq)).

(* === Main Device Process (Loop) === *)
let LevelControlDevice(ep: endpoint) =
  (* Internal state tuple carried over iterations on private channel c_internal.
     Structure: (state, CurrentLevel, device_min_level, device_max_level, OnOff, RemainingTime, CurrentFrequency) *)
  in(c_internal, (st: state, curLevel: level, devMin: level, devMax: level, onoffAttr: boolv, remTime: time, curFreq: frequency));
  DeviceStep(ep, st, curLevel, devMin, devMax, onoffAttr, remTime, curFreq);
  (* recurse *)
  LevelControlDevice(ep).

(* === Main Process === *)
process
  (* Initialize one endpoint with default OffState and symbolic attribute values *)
  new ep0: endpoint;
  new initLevel: level;
  new minLevel: level;
  new maxLevel: level;
  new initFreq: frequency;
  out(c_internal, (st_OffState, initLevel, minLevel, maxLevel, v_false, v_zero_time, initFreq));
  (* Replicated device behavior: attacker can send arbitrary commands on c_cmd *)
  !LevelControlDevice(ep0)

